import type {
	LixStorageConfig,
	LixBinding,
	PluginRuntimeDispatch,
	TelemetryDispatch,
} from "./binding-types.js";

// Generated before TypeScript compilation and emitted beside this module.
// @ts-expect-error Generated by build:wasm.
import initWasm, { openMemoryFromSnapshot } from "./wasm/lix_js_sdk.js";

let wasmInitialized: Promise<unknown> | undefined;

function initializeWasm(): Promise<unknown> {
	return (wasmInitialized ??= initWasm());
}

export async function openLixBinding(
	storage: LixStorageConfig,
	dispatch: PluginRuntimeDispatch,
	telemetry?: TelemetryDispatch,
): Promise<LixBinding> {
	if (storage.kind !== "memory") {
		throw new Error(
			`${storage.kind === "localFilesystem" ? "LocalFilesystem" : "SQLite"} is only available in Node.js`,
		);
	}
	await initializeWasm();
	const openMemory = openMemoryFromSnapshot as unknown as {
		(
			dispatch: PluginRuntimeDispatch,
			telemetry: TelemetryDispatch | undefined,
			snapshot: Uint8Array | undefined,
		): Promise<LixBinding>;
		length: number;
	};
	if (openMemory.length >= 3) {
		return openMemory(dispatch, telemetry, storage.snapshot);
	}
	// The published fallback WASM predates optional telemetry. Its second
	// argument is the snapshot, so passing the current signature would silently
	// discard persisted client state.
	return (
		openMemory as unknown as (
			dispatch: PluginRuntimeDispatch,
			snapshot: Uint8Array | undefined,
		) => Promise<LixBinding>
	)(dispatch, storage.snapshot);
}
